parameters.jsonBody:
={
  "to": "UserID",
  "messages": [
    {
      "type": "flex",
      "altText": "🥇 ราคาทองคำวันนี้",
      "contents": {
        "type": "bubble",
        "header": {
          "type": "box",
          "layout": "vertical",
          "backgroundColor": "#C89A00",
          "contents": [
            {
              "type": "text",
              "text": "🥇 ราคาทองคำวันนี้",
              "color": "#FFFFFF",
              "size": "sm",
              "weight": "bold"
            },
            {
              "type": "text",
              "text": "{{ $('HTTP Request').item.json.response.price.gold.sell }} บาท",
              "color": "#FFFFFF",
              "size": "xxl",
              "weight": "bold"
            },
            {
              "type": "text",
              "text": "{{ $('HTTP Request').item.json.response.update_time }}",
              "color": "#FFE58A",
              "size": "xs"
            }
          ]
        },
        "body": {
          "type": "box",
          "layout": "vertical",
          "contents": [
            {
              "type": "box",
              "layout": "horizontal",
              "contents": [
                {
                  "type": "box",
                  "layout": "vertical",
                  "flex": 1,
                  "contents": [
                    { "type": "text", "text": "ทองรูปพรรณ", "size": "xs", "color": "#888888", "weight": "bold" },
                    { "type": "text", "text": "{{ 'ซื้อ: ' + $('HTTP Request').item.json.response.price.gold.buy }}", "size": "sm", "color": "#16A34A" },
                    { "type": "text", "text": "{{ 'ขาย: ' + $('HTTP Request').item.json.response.price.gold.sell }}", "size": "sm", "color": "#DC2626" }
                  ]
                },
                {
                  "type": "box",
                  "layout": "vertical",
                  "flex": 1,
                  "contents": [
                    { "type": "text", "text": "ทองคำแท่ง", "size": "xs", "color": "#888888", "weight": "bold" },
                    { "type": "text", "text": "{{ 'ซื้อ: ' + $('HTTP Request').item.json.response.price.gold_bar.buy }}", "size": "sm", "color": "#16A34A" },
                    { "type": "text", "text": "{{ 'ขาย: ' + $('HTTP Request').item.json.response.price.gold_bar.sell }}", "size": "sm", "color": "#DC2626" }
                  ]
                }
              ]
            },
            { "type": "separator", "margin": "md" },
            {
              "type": "box",
              "layout": "vertical",
              "margin": "md",
              "contents": [
                { "type": "text", "text": "✨ AI วิเคราะห์", "size": "sm", "weight": "bold", "color": "#5B21B6" },
                {
                  "type": "text",
                  "text": "{{ $('Message a model').item.json.content.parts[0].text }}",
                  "wrap": true,
                  "size": "sm",
                  "color": "#444444",
                  "margin": "sm"
                }
              ]
            }
          ]
        },
        "footer": {
          "type": "box",
          "layout": "horizontal",
          "contents": [
            { "type": "text", "text": "ข้อมูล: YLG Gold", "size": "xs", "color": "#AAAAAA" },
            { "type": "text", "text": "#ราคาทอง", "size": "xs", "color": "#C89A00", "align": "end" }
          ]
        }
      }
    }
  ]
}
